SELECT change_description
FROM image_histories
WHERE user_id = 1002;

SELECT COUNT(*) 
FROM image_processing_jobs 
WHERE status = 'pending';

SELECT category_name, description
FROM image_categories
WHERE category_name = 'Nature';

SELECT format_name
FROM image_formats
WHERE format_id = 1;

SELECT COUNT(*) 
FROM image_category_mappings 
WHERE category_id = 0;

SELECT image_id, rating
FROM image_reviews
WHERE rating = (SELECT MAX(rating) FROM image_reviews);
